+    @Test
+    public void testReinterpretScope() {
+        try (Arena arena = Arena.ofConfined()) {
+            MemorySegment addr = make(14, 99);
+            MemorySegment seg = Point.reinterpret(addr, 1);
+            assertEquals(Point.x(seg), 14);
+            assertEquals(Point.y(seg), 99);
+
